import { NextResponse } from "next/server";
import Groq from "groq-sdk";
import webSearch from "../../utils/webSearch";

const client = new Groq({
    apiKey: process.env.GROQ_API_KEY, // safe on server
});

export async function POST(req: Request) {
    try {
        const { prompt } = await req.json();

        const chatCompletion = await client.chat.completions.create({
            // response_format: {type: "json_object"},
            model: "llama-3.3-70b-versatile",
            messages: [
                {
                    role: "system",
                    content: "You are Clara, a polite smart assistant. You have access to following tools: 1. webSearch({query}): {query: string} // Search latest information and realtime data on the internet",
                },
                {
                    role: "user",
                    content: prompt,
                },
            ],
            "tools": [
                {
                    "type": "function",
                    "function": {
                        "name": "webSearch",
                        "description": "Search the latest information and realtime data on the internet",
                        "parameters": {
                            "type": "object",
                            "properties": {
                                "query": {
                                    "type": "string",
                                    "description": "The search query to perform search on the web"
                                },
                            },
                            "required": ["query"]
                        }
                    }
                }
            ],
            tool_choice: 'auto'
        });

        const choice = chatCompletion.choices[0]?.message;
        if (!choice) {
            console.error("No choices returned in chat completion:", chatCompletion);
            return NextResponse.json({ error: "No response from model" }, { status: 500 });
        }
        console.log(choice?.tool_calls);

        for (const tool of choice?.tool_calls || []) {
            // handle each tool call if needed 
            const functionName = tool?.function?.name;
            const functionParams = tool?.function?.arguments;

            if(functionName === "webSearch") {
                // Call the actual function and get result
                const searchResult = await webSearch(JSON.parse(functionParams));
                console.log(`Tool call result for ${functionName}:`, searchResult);
            }
        }
        console.log(chatCompletion);
        return NextResponse.json({
        text: choice?.content || "",
        tool_calls: !choice?.content ? choice?.tool_calls || [] : [],
        });
        
        // return NextResponse.json({
        //     text: chatCompletion.choices[0]?.message?.content || "",
        // });
    } catch (error: any) {
        console.error("Groq API error:", error);
        return NextResponse.json({ error: error.message }, { status: 500 });
    }
}